  // undefined => not provided
  if (raw === undefined) {
    return undefined;
  }

  const trimmed = String(raw || "").trim();

  // empty string => clear
  if (!trimmed) {
    return null;
  }

  if (!/^https?:\/\//i.test(trimmed)) {
    throw new Error(`${keyLabel} must start with http:// or https://`);
  }

  return trimmed;
}

